const a = [
  {"id":6339,"text":"Carbamoyl phosphate synthetase II (CPS-II) is allosterically inhibited by which of the following?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 302.","responses":[{"text":"Adenosine triphosphate (ATP)","correct":false,"visible":false},{"text":"Uridine monophosphate (UMP)","correct":false,"visible":false},{"text":"Uridine diphosphate (UDP)","correct":false,"visible":false},{"text":"Uridine triphosphate (UTP)","correct":true,"visible":false},{"text":"Phosphoribosyl pyrophosphate (PRPP)","correct":false,"visible":false}]},{"id":6514,"text":"A 32-year-old lady comes to the ultrasound department for an antenatal scan which shows bilateral hydronephrosis, hydro-ureters, and a distended urinary bladder with a keyhole sign in the fetus. The fetus is suspected with a case of posterior urethral valves. She is advised to have a post-natal checkup of the baby. What is the investigation of choice in this particular case?","explanation":null,"reference":"Bingham G, Rentea RM. Posterior urethral valve. In: StatPearls. StatPearls Publishing; 2022. Accessed October 17, 2022. http://www.ncbi.nlm.nih.gov/books/NBK560881/","responses":[{"text":"Kidney, ureter, and bladder (KUB) X-ray","correct":false,"visible":false},{"text":"Voiding cystourethrogram (VCUG)","correct":true,"visible":false},{"text":"Magnetic resonance imaging (MRI)","correct":false,"visible":false},{"text":"Computed tomography scan (CT scan)","correct":false,"visible":false},{"text":"Repeat ultrasound KUB + Prostate","correct":false,"visible":false}]},{"id":6518,"text":"A 4-year-old girl presents with severe pitting edema. Further investigations show hypoalbuminemia, lipiduria, and 3.8 g proteinuria. Biopsy confirms the renal disease. Which of the following best describes the pathophysiology of proteinuria in this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 128.","responses":[{"text":"Tubulointerstitial damage","correct":false,"visible":false},{"text":"Crescent formation in the glomeruli","correct":false,"visible":false},{"text":"Derangement in glomerular capillary walls","correct":true,"visible":false},{"text":"Anti–glomerular basement membrane (anti-GBM) antibodies cross reacting with alveolar basement membranes","correct":false,"visible":false},{"text":"Excess dietary protein intake","correct":false,"visible":false}]},{"id":6530,"text":"Which of the following is formed as a result of deamination of cytosine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 428.","responses":[{"text":"Methyl cytosine","correct":false,"visible":false},{"text":"Adenine","correct":false,"visible":false},{"text":"Uracil","correct":true,"visible":false},{"text":"Cytidylic acid","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false}]},{"id":6556,"text":"A 5-year-old boy presents with generalized edema and periorbital edema. Further investigations show hypoalbuminemia, lipiduria, and 3.7 g proteinuria. Which of the following conditions is the most likely cause in this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 127.","responses":[{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false},{"text":"Rapidly progressive glomerulonephritis","correct":false,"visible":false},{"text":"Amyloidosis","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false}]},{"id":6662,"text":"Amina has recently completed her FCPS and now she is pursuing her career as a specialist. She was passionate about this field and always wanted to serve society and live a meaningful life. Which of the following approach of happiness most likely focuses on meaning and self-realization?","explanation":null,"reference":"The best within us: positive psychology perspectives on eudaimonia. https://www.apa.org. Accessed October 19, 2022. https://www.apa.org/pubs/books/4318113","responses":[{"text":"Hedonism","correct":false,"visible":false},{"text":"Eudemonia","correct":true,"visible":false},{"text":"Subjective well being","correct":false,"visible":false},{"text":"Psychological well-being","correct":false,"visible":false},{"text":"Happiness","correct":false,"visible":false}]},{"id":6663,"text":"What is the alkaline nature of the extracellular fluid and acidic urine termed as?","explanation":null,"reference":"Schoaps RS, Hazard SW, Docimo Jr. S, Pauli EM. Paradoxical aciduria. Clinical Algorithms in General Surgery : A Practical Guide. https://link.springer.com/chapter/10.1007/978-3-319-98497-1_188","responses":[{"text":"Glucosuria","correct":false,"visible":false},{"text":"Phenyl ketonuria","correct":false,"visible":false},{"text":"Ketonuria","correct":false,"visible":false},{"text":"Amino aciduria","correct":false,"visible":false},{"text":"Paradoxical aciduria","correct":true,"visible":false}]},{"id":6671,"text":"An adult male had a road traffic accident and went into a hypovolemic shock due to blood loss. Which intravenous fluid is preferable to start as initial available therapy in an emergency?","explanation":null,"reference":"Haemaccel - summary of product characteristics (Smpc) -(Emc). Accessed October 19, 2022. https://www.medicines.org.uk/emc/product/13176/smpc#gref","responses":[{"text":"Haemaccel","correct":true,"visible":false},{"text":"Ringer's lactate","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Amino acid solution","correct":false,"visible":false},{"text":"5% dextrose water","correct":false,"visible":false}]},{"id":6685,"text":"In a 60-year-old diabetic patient, a routine lab investigation shows hemoglobin: 8.2 gm/dL, creatinine (Cr): 5.0 mg/dL, calcium (Ca): 6.7 mg/dL, phosphate(PO4): 5.2 mg/dL, with small kidneys on ultrasound. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132, 133.","responses":[{"text":"Acute kidney injury","correct":false,"visible":false},{"text":"Glomerulonephritis","correct":false,"visible":false},{"text":"Urinary tract infection","correct":false,"visible":false},{"text":"Chronic kidney disease","correct":true,"visible":false},{"text":"Acute interstitial nephritis","correct":false,"visible":false}]},{"id":6686,"text":"In a patient with severe dehydration, the plasma osmolality increases. This is corrected by which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 233.","responses":[{"text":"Angiotensin-II","correct":false,"visible":false},{"text":"Aldosterone","correct":false,"visible":false},{"text":"Antidiuretic hormone (ADH)","correct":true,"visible":false},{"text":"Increased intake of glucose","correct":false,"visible":false},{"text":"Increase in protein intake","correct":false,"visible":false}]},{"id":6693,"text":"Which one of the following confirms the diagnosis of gout?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 1014.","responses":[{"text":"Presence of urate crystals in the synovial fluid","correct":true,"visible":false},{"text":"Renal stones","correct":false,"visible":false},{"text":"Redness and pain in joints","correct":false,"visible":false},{"text":"Increased uric acid excretion in urine","correct":false,"visible":false},{"text":"Hyperuricemia","correct":false,"visible":false}]},{"id":6712,"text":"In purine metabolism, what does the deamination of guanine yield?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 299.","responses":[{"text":"Thiamine","correct":false,"visible":false},{"text":"Xanthine","correct":true,"visible":false},{"text":"Methyl guanine","correct":false,"visible":false},{"text":"Uracil","correct":false,"visible":false},{"text":"Cytidylic acid","correct":false,"visible":false}]},{"id":6716,"text":"Mr. Mughees did not score well in the exam. He has pessimistic explanatory styles and attributed his failure to generalized bad luck i.e. 'I always had bad luck in all life situations' (stable and global attribution), which lead to him being depressed. Which one of the following could preferably explain the causes of negative events contrary to this pessimistic explanatory style?","explanation":null,"reference":null,"responses":[{"text":"Internal, stable","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"External, unstable, specific","correct":false,"visible":false},{"text":"External, global, stable","correct":false,"visible":false},{"text":"Internal, specific, unstable","correct":true,"visible":false}]},{"id":6721,"text":"Which of the following is carbamoyl phosphate a precursor of?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 253.","responses":[{"text":"Uric acid","correct":false,"visible":false},{"text":"Urea","correct":true,"visible":false},{"text":"Hypoxanthine","correct":false,"visible":false},{"text":"Xanthine","correct":false,"visible":false},{"text":"Ionosine","correct":false,"visible":false}]},{"id":6746,"text":"What does renal correction of acute hyperkalemia result in?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 415.","responses":[{"text":"Increased secretion of H+","correct":false,"visible":false},{"text":"Alkalosis","correct":false,"visible":false},{"text":"Increased secretion of HCO3-","correct":false,"visible":false},{"text":"Increased secretion of Na+","correct":false,"visible":false},{"text":"Acidosis","correct":true,"visible":false}]},{"id":6759,"text":"Which of the following do the afferent arterioles arise from?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 323.","responses":[{"text":"Peritubular capillaries","correct":false,"visible":false},{"text":"Intralobar artery","correct":false,"visible":false},{"text":"Interlobar artery","correct":false,"visible":false},{"text":"Arcuate artery","correct":false,"visible":false},{"text":"Interlobular artery","correct":true,"visible":false}]},{"id":6762,"text":"What is the end product of purine metabolism in humans?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 298.","responses":[{"text":"Xanthine","correct":false,"visible":false},{"text":"Uric acid","correct":true,"visible":false},{"text":"Hypoxanthine","correct":false,"visible":false},{"text":"Urea","correct":false,"visible":false},{"text":"Inositol","correct":false,"visible":false}]},{"id":6770,"text":"What is the most sensitive indicator of glomerular function?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 361.","responses":[{"text":"Serum ammonia","correct":false,"visible":false},{"text":"Creatinine clearance","correct":true,"visible":false},{"text":"Serum creatinine","correct":false,"visible":false},{"text":"Serum urea","correct":false,"visible":false},{"text":"Urea clearance","correct":false,"visible":false}]},{"id":6787,"text":"The substance is freely filtered at the glomerular capillaries but is not excreted into the urine because all the filtered substance is reabsorbed from the tubules back into the blood. This pattern occurs for which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 329.","responses":[{"text":"Electrolytes","correct":false,"visible":false},{"text":"Bases","correct":false,"visible":false},{"text":"Inulin","correct":false,"visible":false},{"text":"Creatinine","correct":false,"visible":false},{"text":"Amino acids and glucose","correct":true,"visible":false}]},{"id":6789,"text":"This substance is freely filtered at the glomerular capillaries and is not reabsorbed, but additional quantities of this substance are secreted from the peritubular capillary blood into the renal tubules. Which substance is this?","explanation":null,"reference":null,"responses":[{"text":"Organic acids and bases","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false},{"text":"Amino acids and glucose","correct":false,"visible":false},{"text":"Creatinine","correct":true,"visible":false},{"text":"Inulin","correct":false,"visible":false}]},{"id":6791,"text":"This substance is freely filtered by the glomerular capillaries but is neither reabsorbed nor secreted. Therefore, its excretion rate is equal to the rate at which it was filtered. Which substance is this?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 355.","responses":[{"text":"Glucose","correct":false,"visible":false},{"text":"Electrolytes","correct":false,"visible":false},{"text":"Inulin","correct":true,"visible":false},{"text":"Creatinine","correct":false,"visible":false},{"text":"Amino acids","correct":false,"visible":false}]},{"id":6797,"text":"Which of the following gives rise to the trigone of the bladder?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: \r\n255.","responses":[{"text":"Paramesonephric duct","correct":false,"visible":false},{"text":"Splanchnic mesoderm","correct":false,"visible":false},{"text":"Mullerian duct","correct":false,"visible":false},{"text":"Endoderm","correct":false,"visible":false},{"text":"Mesonephric duct","correct":true,"visible":false}]},{"id":6800,"text":"Which of the following is the correct sequence of branching pattern of renal arteries?","explanation":null,"reference":null,"responses":[{"text":"Segmental artery \u003e lobar artery \u003e intralobular artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Lobar artery \u003e segmental artery \u003e intralobular artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Segmental artery \u003e interlobar artery \u003e lobar artery \u003e arcuate artery","correct":false,"visible":false},{"text":"Segmental artery \u003e lobar artery \u003e interlobar artery \u003e arcuate artery","correct":true,"visible":false},{"text":"Lobar artery \u003e segmental artery \u003e interlobar artery \u003e arcuate artery","correct":false,"visible":false}]},{"id":6812,"text":"Which of the following cells release the enzyme renin?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 236.","responses":[{"text":"Juxtaglomerular cells","correct":true,"visible":false},{"text":"Interstitial kidney cells","correct":false,"visible":false},{"text":"Parietal epithelial cells","correct":false,"visible":false},{"text":"Brush border cells","correct":false,"visible":false},{"text":"Glomerulus parietal cells","correct":false,"visible":false}]},{"id":6816,"text":"Which of the following forms the outermost layer of the kidney?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 377.","responses":[{"text":"Perinephric fat","correct":false,"visible":false},{"text":"Renal fascia","correct":true,"visible":false},{"text":"Peritoneum","correct":false,"visible":false},{"text":"Only fat","correct":false,"visible":false},{"text":"Fibrous capsule","correct":false,"visible":false}]},{"id":6827,"text":"An increase in which of the following leads to a subsequent decrease in the glomerular filtration rate?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 333.","responses":[{"text":"Glomerular capillary hydrostatic pressure","correct":false,"visible":false},{"text":"Bowman's capsule plasma oncotic pressure","correct":false,"visible":false},{"text":"Peritubular capillary hydrostatic pressure","correct":false,"visible":false},{"text":"Glomerular capillary plasma oncotic pressure","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":6839,"text":"Which of the following is involved in the counter-current multiplier mechanism of kidneys?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 368.","responses":[{"text":"Proximal convoluted tubules","correct":false,"visible":false},{"text":"Vasa recta","correct":false,"visible":false},{"text":"Glomerulus","correct":false,"visible":false},{"text":"Peritubular arteries","correct":false,"visible":false},{"text":"Loop of Henle","correct":true,"visible":false}]},{"id":6869,"text":"Which of the following structures is only found in the renal medulla?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 323.","responses":[{"text":"Bowman's capsule","correct":false,"visible":false},{"text":"Minor calyces","correct":false,"visible":false},{"text":"Distal convoluted tubule","correct":false,"visible":false},{"text":"Collecting tubules","correct":false,"visible":false},{"text":"Thin limb of loop of Henle","correct":true,"visible":false}]},{"id":7569,"text":"What is the most common causative organism for acute pyelonephritis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132.","responses":[{"text":"Escherichia coli","correct":true,"visible":false},{"text":"Enterobacter","correct":false,"visible":false},{"text":"Pseudomonas aeroginosa","correct":false,"visible":false},{"text":"Proteus mirabilis","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false}]},{"id":8736,"text":"What effect does exogenous erythropoietin have on a patient who has end-stage renal disease with anemia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 419.","responses":[{"text":"Decreased blood volume","correct":false,"visible":false},{"text":"Decreased blood pressure","correct":false,"visible":false},{"text":"Induces hypoxia","correct":false,"visible":false},{"text":"Increased blood pressure","correct":true,"visible":false},{"text":"Decreased erythrocyte production","correct":false,"visible":false}]},{"id":8748,"text":"Erythropoietin is primarily formed in which organ?","explanation":"**Erythropoietin (EPO)** is primarily formed in the **kidneys**, specifically in the interstitial cells located in the peritubular capillaries of the renal cortex and outer medulla. A small amount of EPO is also produced in the liver.\r\n\r\nEPO is a glycoprotein hormone that plays a crucial role in regulating red blood cell production. It stimulates the production of red blood cells from hematopoietic stem cells in the bone marrow. EPO is released in response to decreased oxygen levels in the blood, detected by specialized cells in the kidneys called peritubular fibroblasts. Hypoxia-inducible factor (HIF) is activated in these cells, leading to the synthesis and secretion of EPO.\r\n\r\nThe production of EPO by the kidneys is tightly regulated to maintain the appropriate oxygen-carrying capacity of the blood. Conditions such as hypoxia, anemia, and renal disease can influence EPO production and lead to alterations in red blood cell production.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 414.","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"Bone marrow","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Kidneys","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false}]},{"id":8750,"text":"The hilum of the kidney is located in which plane?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 517.","responses":[{"text":"Median plane","correct":false,"visible":false},{"text":"Supine plane","correct":false,"visible":false},{"text":"Transpyloric plane","correct":true,"visible":false},{"text":"Transtubercular plane","correct":false,"visible":false},{"text":"Subcostal plane","correct":false,"visible":false}]},{"id":9352,"text":"What is the arrangement of structures at the hilum of the kidney from anterior to posterior?","explanation":null,"reference":null,"responses":[{"text":"Renal pelvis, vein, artery","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Vein, artery, renal pelvis","correct":true,"visible":false},{"text":"Artery, vein, renal pelvis","correct":false,"visible":false},{"text":"Renal pelvis, artery, vein","correct":false,"visible":false}]},{"id":9353,"text":"The nephron is the functional unit of a kidney. Which of the following structures does urine pass through before entering the ureter?","explanation":null,"reference":null,"responses":[{"text":"Proximal convoluted tubule","correct":false,"visible":false},{"text":"Renal pelvis","correct":true,"visible":false},{"text":"Glomerulus","correct":false,"visible":false},{"text":"Loop of Henle","correct":false,"visible":false},{"text":"Distal convoluted tubule","correct":false,"visible":false}]},{"id":9354,"text":"A 63-year-old female came to the outpatient department with complaints of fever, peristaltic pain, and hematuria. Her ultrasound reports revealed calculi in the conducting part of the urinary system. Where are the calculi most likely found?","explanation":null,"reference":null,"responses":[{"text":"Minor calyx","correct":false,"visible":false},{"text":"Major calyx","correct":false,"visible":false},{"text":"Ureterovesical part of ureter","correct":true,"visible":false},{"text":"Pelvis","correct":false,"visible":false},{"text":"Renal columns","correct":false,"visible":false}]},{"id":9355,"text":"Which of the following is the false statement regarding the posterior relations of the right kidney?","explanation":null,"reference":null,"responses":[{"text":"12th rib","correct":false,"visible":false},{"text":"Quadratus lumborum","correct":false,"visible":false},{"text":"Psoas major","correct":false,"visible":false},{"text":"Iliohypogastric nerve","correct":false,"visible":false},{"text":"11th rib","correct":true,"visible":false}]},{"id":9357,"text":"Which of the following structures lie in the center of the renal lobule?","explanation":null,"reference":null,"responses":[{"text":"Interlobar artery","correct":false,"visible":false},{"text":"Cortical column","correct":false,"visible":false},{"text":"Medullary ray","correct":true,"visible":false},{"text":"Arcuate artery","correct":false,"visible":false},{"text":"Renal hilum","correct":false,"visible":false}]},{"id":9358,"text":"A 2nd-year medical student is looking at a histology slide of tissue with a narrow lumen lined by transitional epithelium. He can observe 3 layers of smooth muscles in its wall. Which structure is he observing?","explanation":null,"reference":null,"responses":[{"text":"Vas deferens","correct":false,"visible":false},{"text":"Urethra","correct":false,"visible":false},{"text":"Prostate","correct":false,"visible":false},{"text":"Urinary bladder","correct":false,"visible":false},{"text":"Ureter","correct":true,"visible":false}]},{"id":9359,"text":"Which of the following histological features is not specific to the proximal convoluted tubule?","explanation":null,"reference":null,"responses":[{"text":"They have striated borders due to basal infoldings of plasma membrane","correct":false,"visible":false},{"text":"They are lined by simple cuboidal/low columnar epithelium","correct":false,"visible":false},{"text":"They have microvilli on their luminal surfaces forming a brush border","correct":false,"visible":false},{"text":"They are more eosinophilic due to numerous mitochondria","correct":false,"visible":false},{"text":"They do not have a typical brush border as compared to the distal convoluted tubule","correct":true,"visible":false}]},{"id":9361,"text":"A double ureter anomaly results from the failure of normal development of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Metanephros","correct":false,"visible":false},{"text":"Pronephros","correct":false,"visible":false},{"text":"Mesonephros (Wolffian) duct","correct":false,"visible":false},{"text":"Ureteric bud","correct":true,"visible":false},{"text":"Paramesonephric duct","correct":false,"visible":false}]},{"id":9362,"text":"What is the most abundant buffer in the proximal tubular fluid?","explanation":null,"reference":null,"responses":[{"text":"Ammonia","correct":false,"visible":false},{"text":"Phosphate","correct":true,"visible":false},{"text":"Lactate","correct":false,"visible":false},{"text":"Protein","correct":false,"visible":false},{"text":"Bicarbonate","correct":false,"visible":false}]},{"id":9363,"text":"What is the principle mechanism of H+ ion secretion into the proximal convoluted tubule?","explanation":null,"reference":null,"responses":[{"text":"H-ATPase","correct":false,"visible":false},{"text":"Na-H symport","correct":false,"visible":false},{"text":"Na-H exchanger","correct":true,"visible":false},{"text":"H-Ca exchanger","correct":false,"visible":false},{"text":"H-HCO₃-ATPase","correct":false,"visible":false}]},{"id":9364,"text":"At what volume of urine, is the micturition reflex initiated?","explanation":null,"reference":null,"responses":[{"text":"250 ml - 300 ml","correct":false,"visible":false},{"text":"150 ml -200 ml","correct":false,"visible":false},{"text":"300 ml - 400 ml","correct":true,"visible":false},{"text":"450 ml - 500 ml","correct":false,"visible":false},{"text":"100 ml - 150 ml","correct":false,"visible":false}]},{"id":9365,"text":"What is the dietary effect of high protein intake and increased blood glucose on renal nephrons?","explanation":null,"reference":null,"responses":[{"text":"Increase Bowman's capsule hydrostatic pressure","correct":false,"visible":false},{"text":"Increase afferent arteriolar constriction","correct":false,"visible":false},{"text":"Increase efferent arteriolar constriction","correct":false,"visible":false},{"text":"Increase glomerular colloid oncotic pressure","correct":false,"visible":false},{"text":"Increase sodium reabsorption in proximal convoluted tubules","correct":true,"visible":false}]},{"id":9367,"text":"The clearance of which endogenously produced substance is used to assess normal renal function?","explanation":null,"reference":null,"responses":[{"text":"Urea","correct":false,"visible":false},{"text":"Para-amino hippuric acid (PAH)","correct":false,"visible":false},{"text":"Potassium ions","correct":false,"visible":false},{"text":"Creatinine","correct":true,"visible":false},{"text":"Inulin","correct":false,"visible":false}]},{"id":9368,"text":"What may the kidneys enhance in response to acidosis?","explanation":"Acidosis indicates an accumulation of H⁺ ions in the body, leading to a decreased blood pH. In response to acidosis, the kidneys play a pivotal role in restoring acid-base balance by:\r\n\r\n1. **Enhancing the secretion of H⁺ ions:** The primary response to acidosis is an increased secretion of hydrogen ions (H⁺) in the renal tubules, allowing their elimination in urine. This helps in reducing the overall H⁺ concentration in the blood.\r\n\r\n2. **Reabsorbing bicarbonate (HCO₃⁻) ions:** As H⁺ ions are secreted, HCO₃⁻ ions are simultaneously reabsorbed into the blood from the renal tubules. This bicarbonate reabsorption aids in buffering the excess H⁺ ions, further helping to restore the acid-base balance.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 410.","responses":[{"text":"Secretion of Na⁺ ions","correct":false,"visible":false},{"text":"Secretion of HCO₃⁻","correct":false,"visible":false},{"text":"Secretion of K⁺ ions","correct":false,"visible":false},{"text":"Urea retention","correct":false,"visible":false},{"text":"Secretion of H⁺ ions","correct":true,"visible":false}]},{"id":9369,"text":"What do the kidneys enhance in response to alkalosis?","explanation":null,"reference":null,"responses":[{"text":"N₂-retention","correct":false,"visible":false},{"text":"Secretion of H⁺ ions","correct":false,"visible":false},{"text":"Secretion of K⁺ ions","correct":false,"visible":false},{"text":"Secretion of HCO₃⁻","correct":true,"visible":false},{"text":"Secretion of Na⁺ ions","correct":false,"visible":false}]},{"id":9370,"text":"Which of the following will decrease the amount of potassium excreted from the kidney?","explanation":null,"reference":null,"responses":[{"text":"Circulating level of aldosterone increases","correct":false,"visible":false},{"text":"The excretion of organic ions increase","correct":false,"visible":false},{"text":"Na+ reabsorption by the distal nephron decreases","correct":true,"visible":false},{"text":"Dietary intake of potassium increases","correct":false,"visible":false},{"text":"Distal tubular flow increases","correct":false,"visible":false}]},{"id":9371,"text":"How can the body get rid of the huge acid load produced by metabolic reactions?","explanation":null,"reference":null,"responses":[{"text":"Breathe faster and more deeply","correct":false,"visible":false},{"text":"Increase the concentration of protein ions in the plasma","correct":false,"visible":false},{"text":"Excrete hydrogen ions into the urine","correct":true,"visible":false},{"text":"Increase lipids in the blood","correct":false,"visible":false},{"text":"Increase the concentration of sodium ions","correct":false,"visible":false}]},{"id":9372,"text":"A 10-year-old boy develops severe diarrhea while traveling to South Asia. The laboratory investigation revealed the following: arterial blood pH = 7.25, partial pressure of carbon dioxide = 24 mmHg, bicarbonate = 10 mEq/L, normal anion gap. What is the correct diagnosis of this patient?","explanation":null,"reference":null,"responses":[{"text":"Hypercapnea","correct":false,"visible":false},{"text":"Respiratory alkalosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":false,"visible":false},{"text":"Respiratory acidosis","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":true,"visible":false}]},{"id":9373,"text":"Which hormone regulates sodium and water content in the human body?","explanation":null,"reference":null,"responses":[{"text":"Prolactin","correct":false,"visible":false},{"text":"Anti-diuretic hormone","correct":true,"visible":false},{"text":"Oxytocin","correct":false,"visible":false},{"text":"Cortisone","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false}]},{"id":9374,"text":"What is the normal plasma sodium concentration?","explanation":null,"reference":null,"responses":[{"text":"135 to 145 mEq/L","correct":true,"visible":false},{"text":"85 to 105 mEq/L","correct":false,"visible":false},{"text":"35 to 75 mEq/L","correct":false,"visible":false},{"text":"155 to 175 mEq/L","correct":false,"visible":false},{"text":"115 to 125 mEq/L","correct":false,"visible":false}]},{"id":9375,"text":"Where is the largest portion of water (28 liters) present?","explanation":null,"reference":null,"responses":[{"text":"Intracellular compartment","correct":true,"visible":false},{"text":"Blood","correct":false,"visible":false},{"text":"Cerebrospinal fluid","correct":false,"visible":false},{"text":"Extracellular compartment","correct":false,"visible":false},{"text":"Interstitial compartment","correct":false,"visible":false}]},{"id":9379,"text":"Ionization of water is the basis of which of the following?","explanation":null,"reference":null,"responses":[{"text":"Solubility","correct":false,"visible":false},{"text":"pH scale","correct":true,"visible":false},{"text":"Viscosity","correct":false,"visible":false},{"text":"Diffusion","correct":false,"visible":false},{"text":"Adsorption","correct":false,"visible":false}]},{"id":9381,"text":"What is the predominant cation of plasma?","explanation":null,"reference":null,"responses":[{"text":"Ca⁺²","correct":false,"visible":false},{"text":"Mg⁺²","correct":false,"visible":false},{"text":"Fe⁺²","correct":false,"visible":false},{"text":"Na⁺","correct":true,"visible":false},{"text":"K⁺","correct":false,"visible":false}]},{"id":9382,"text":"What is the normal plasma potassium reference value?","explanation":null,"reference":null,"responses":[{"text":"3.5 - 5.4 mEq/L","correct":true,"visible":false},{"text":"1 - 2.2 mEq/L","correct":false,"visible":false},{"text":"5.5 - 7.6 mEq/L","correct":false,"visible":false},{"text":"1.5 - 2.5 mEq/L","correct":false,"visible":false},{"text":"6.5 - 7.7 mEq/L","correct":false,"visible":false}]},{"id":9385,"text":"A 41-year-old has had recurrent urinary tract infections for 15 years. On many of these occasions, Proteus mirabilis was cultured from his urine. For the past 4 days, he has had burning pain while urinating, and urinary frequency. On examination, his temperature is 37.9°C, pulse is 70/min, and blood pressure is 135/85 mmHg. There is marked tenderness on deep pressure over the right costovertebral angle and on deep abdominal palpation. Urinalysis shows a pH of 7.5, specific gravity 1.020, 1+ hematuria, and no protein, glucose, or ketones. Microscopic examination of the urine shows many RBCs, WBCs, and triple phosphate crystals. Which of the following renal lesions is most likely to be present?","explanation":null,"reference":null,"responses":[{"text":"Acute tubular necrosis","correct":false,"visible":false},{"text":"Malignant nephrosclerosis","correct":false,"visible":false},{"text":"Papillary necrosis","correct":false,"visible":false},{"text":"Renal cell carcinoma","correct":false,"visible":false},{"text":"Staghorn calculus","correct":true,"visible":false}]},{"id":9386,"text":"Normal blood levels of urea and creatinine is critical for survival. What are the raised levels of urea and creatinine with clinical features known as?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 896.","responses":[{"text":"Uremic coma","correct":false,"visible":false},{"text":"Azotemia","correct":false,"visible":false},{"text":"Renal failure","correct":false,"visible":false},{"text":"Uremia","correct":true,"visible":false},{"text":"Chronic pyelonephritis","correct":false,"visible":false}]},{"id":9387,"text":"Immunologic mechanisms underlie most forms of glomerular disorders. Which of the following immunologic mechanisms of glomerular injuries is most common?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 901.","responses":[{"text":"Type-1 hypersensitivty reaction","correct":false,"visible":false},{"text":"Antibody-mediated injury","correct":true,"visible":false},{"text":"Activation of alternative complement pathway","correct":false,"visible":false},{"text":"Cell-mediated injury","correct":false,"visible":false},{"text":"Activation of intrinsic coagulation pathway","correct":false,"visible":false}]},{"id":9388,"text":"A 78-year-old man is admitted to a hospital due to acute urinary tract obstruction. For the past few years, he has had concurrent bouts of cystitis. Two days before being admitted to the hospital, he could not urinate at all. What is the most probable cause of bladder outlet obstruction in this patient?","explanation":null,"reference":null,"responses":[{"text":"Prostatic adenocarcinoma","correct":false,"visible":false},{"text":"Nodular prostatic hyperplasia","correct":true,"visible":false},{"text":"Urethral stricture","correct":false,"visible":false},{"text":"Urothelial cell carcinoma of the bladder","correct":false,"visible":false},{"text":"Nephrogenic metaplasia","correct":false,"visible":false}]},{"id":9389,"text":"A 35-year-old man came to the outpatient department with complaints of repeated urinary tract infections. His urine D/R reports show pus cells = 12-15/High power field (HPF), red blood cells = 3-5/HPF, and triple phosphate crystals in the urine. Which of the following could be the cause of infection in such a case?","explanation":null,"reference":null,"responses":[{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Serratia","correct":false,"visible":false},{"text":"Proteus mirabilis","correct":true,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Enterobacter","correct":false,"visible":false}]},{"id":9390,"text":"A 36-year-old married lady came to the outpatient department with a history of flank pain and difficulty in micturition. She also gave a history of weakness, fever in the evening, and a feeling of ill-health. She had not been feeling like eating recently. Her urine D/R showed 25-30 pus cells/High power field (HPF). Her erythrocyte sedimentation rate was 125 in the first hour. Her culture report was negative. What could've been the cause of her illness?","explanation":null,"reference":null,"responses":[{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Proteus mirabilis","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Mycobacterium tuberculosis","correct":true,"visible":false}]},{"id":9391,"text":"Which of the following research types is aimed at discovering the underlying subjective views or experiences, motives, and desires, finding reasons for human behavior (i.e., why people think or do certain things)?","explanation":null,"reference":null,"responses":[{"text":"Quantitative research","correct":false,"visible":false},{"text":"Medical research","correct":false,"visible":false},{"text":"Hospital based research","correct":false,"visible":false},{"text":"Clinical research","correct":false,"visible":false},{"text":"Qualitative research","correct":true,"visible":false}]},{"id":9392,"text":"A 36-year-old is diagnosed with colorectal cancer. As the treating physician, it is your duty to educate him regarding the nature of his illness and its treatment. It is supposed to be conducted in a detailed and professional manner, using simple language which he will understand. What is this process called?","explanation":null,"reference":null,"responses":[{"text":"Informational care","correct":true,"visible":false},{"text":"Crises intervention","correct":false,"visible":false},{"text":"Psychotherapy","correct":false,"visible":false},{"text":"Research","correct":false,"visible":false},{"text":"Counselling","correct":false,"visible":false}]},{"id":9393,"text":"A 55-year-old female patient belonging to a rural area of Balochistan presented to you in the outpatient department and was diagnosed with diabetes. She is accompanied by her 14-year-old son who speaks and understands Urdu partially while the patient does not. You need to provide informational care to the patient but the language is an obstacle. Which of the following would be the appropriate course of action in this case?","explanation":null,"reference":null,"responses":[{"text":"Admit the patient till you can find a doctor who speaks their language","correct":false,"visible":false},{"text":"Prescribe medication and do not provide informational care","correct":false,"visible":false},{"text":"Provide informational care to her son","correct":false,"visible":false},{"text":"Ask a colleague who speaks their language to provide informational care to the patient","correct":true,"visible":false},{"text":"Refer her to a doctor in Balochistan","correct":false,"visible":false}]},{"id":9394,"text":"What is the most important investigation for differentiating between renal and pre-renal acute renal failure?","explanation":null,"reference":null,"responses":[{"text":"Computed tomography (CT) pyelogram","correct":false,"visible":false},{"text":"Serum creatinine","correct":false,"visible":false},{"text":"Urine detailed report","correct":true,"visible":false},{"text":"Arterial blood gases","correct":false,"visible":false},{"text":"Ultrasound kidneys, ureters, and bladder (KUB)","correct":false,"visible":false}]},{"id":9395,"text":"What is the most common cause of acute renal injury?","explanation":null,"reference":null,"responses":[{"text":"Acute tubular necrosis","correct":true,"visible":false},{"text":"Acute glomerulonephritis","correct":false,"visible":false},{"text":"Pre-renal failure","correct":false,"visible":false},{"text":"Post-renal failure","correct":false,"visible":false},{"text":"Tubulo-interstitial nephritis","correct":false,"visible":false}]},{"id":9396,"text":"You visit a patient in the intensive care unit. The patient is a thin elderly female with a history of femur fracture and has been bed-bound for the past 1 year. While going through her lab values, you notice a sodium concentration of 125 mmol/L. The patient is asymptomatic for the signs of hyponatremia and is euvolemic. What first step will you take after looking at the sodium?","explanation":null,"reference":null,"responses":[{"text":"Repeat sodium","correct":false,"visible":false},{"text":"Add sodium chloride tablet","correct":false,"visible":false},{"text":"Free water restriction","correct":true,"visible":false},{"text":"Start hypertonic saline immediately","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":9397,"text":"What is the composition of sodium and chloride in 0.9% normal saline?","explanation":null,"reference":null,"responses":[{"text":"Na 159, Cl 154","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Na 154, Cl 154","correct":true,"visible":false},{"text":"Na 154, Cl 150","correct":false,"visible":false},{"text":"Na 150, Cl 154","correct":false,"visible":false}]},{"id":9398,"text":"A 10-year-old male presents with palpable purpura in the lower extremities and buttocks area. Investigations reveal a decreased glomerular filtration rate (GFR) with a nephritic picture. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Minimal change disease","correct":false,"visible":false},{"text":"Systemic lupus erythematosus","correct":false,"visible":false},{"text":"Focal segmental glomerulosclerosis","correct":false,"visible":false},{"text":"Henoch-Schönlein purpura","correct":true,"visible":false},{"text":"Post streptococcal glomerulonephritis","correct":false,"visible":false}]},{"id":9399,"text":"What is the primary indication for micturating cystourethrography?","explanation":null,"reference":null,"responses":[{"text":"Acute urinary tract infection","correct":false,"visible":false},{"text":"Vesicoureteric reflux","correct":true,"visible":false},{"text":"Fistula","correct":false,"visible":false},{"text":"Urethral trauma","correct":false,"visible":false},{"text":"Urethral malignancy","correct":false,"visible":false}]},{"id":11233,"text":"Which of the following is the gold standard for diagnosing Helicobacter pylori?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 800.","responses":[{"text":"Histopathology","correct":false,"visible":false},{"text":"Urease test","correct":false,"visible":false},{"text":"Urea breath test","correct":false,"visible":false},{"text":"Microbiological culture","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":12105,"text":"Allopurinol is a structural analog of which of the following compounds?","explanation":"Allopurinol is primarily used as a treatment for gout and is known to inhibit the enzyme xanthine oxidase. This enzyme is responsible for the oxidation of hypoxanthine to xanthine and subsequently the oxidation of xanthine to uric acid. By inhibiting xanthine oxidase, allopurinol prevents the formation of uric acid, thereby reducing its levels in the blood.\r\n\r\nAllopurinol's ability to inhibit xanthine oxidase is due to its structural similarity to the natural substrate of the enzyme, **hypoxanthine**. As a structural analog of hypoxanthine, allopurinol can bind to xanthine oxidase, acting as a competitive inhibitor. This leads to decreased uric acid production, which is beneficial in conditions like gout, where there's an overproduction or under-excretion of uric acid.","reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 301.","responses":[{"text":"Uric acid","correct":false,"visible":false},{"text":"Xanthine oxidase","correct":false,"visible":false},{"text":"Inosine monophosphate","correct":false,"visible":false},{"text":"Phosphoribosyl pyrophosphate","correct":false,"visible":false},{"text":"Hypoxanthine","correct":true,"visible":false}]},{"id":12106,"text":"What is the osmolarity of the glomerular filtrate that enters the proximal convoluted tubule?","explanation":"The glomerular filtrate is essentially plasma without proteins. As it's filtered from the glomerulus into Bowman's capsule, its osmolarity is approximately the same as that of plasma. The normal osmolarity of plasma is around **300 mOsm/L**. Thus, the osmolarity of the glomerular filtrate that enters the proximal convoluted tubule is also 300 mOsm/L. As the filtrate travels through the various segments of the nephron, its osmolarity will change due to reabsorption and secretion of solutes and water. For instance, in the descending loop of Henle, water is reabsorbed making the filtrate more concentrated, while in the thick ascending limb, solutes are reabsorbed without water, making the filtrate more dilute. However, at the very beginning, in the proximal tubule, it maintains the osmolarity of plasma.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 366.","responses":[{"text":"300 mOsm/L","correct":true,"visible":false},{"text":"100 mOsm/L","correct":false,"visible":false},{"text":"1200 mOsm/L","correct":false,"visible":false},{"text":"400 mOsm/L","correct":false,"visible":false},{"text":"200 mOsm/L","correct":false,"visible":false}]},{"id":12108,"text":"In which lymph nodes does the abdominal part of the ureter drain?","explanation":null,"reference":"(1) Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 522. \r\n\r\n(2) Lescay HA, Jiang J, Tuma F. Anatomy, abdomen and pelvis, ureter. In: StatPearls. StatPearls Publishing; 2022. Accessed October 9, 2022. http://www.ncbi.nlm.nih.gov/books/NBK532980/","responses":[{"text":"Deep inguinal nodes","correct":false,"visible":false},{"text":"External iliac nodes","correct":false,"visible":false},{"text":"Common iliac nodes","correct":false,"visible":false},{"text":"Paraaortic nodes","correct":true,"visible":false},{"text":"Internal iliac nodes","correct":false,"visible":false}]},{"id":12109,"text":"A 25-year-old male presented to the outpatient department with symptoms of nephrotic syndrome. The biopsy showed normal histology with effacement of foot processes on electron microscopy. Which disease is he likely to have?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 128.","responses":[{"text":"Acute pyelonephritis","correct":false,"visible":false},{"text":"Chronic pyelonephritis","correct":false,"visible":false},{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Rapidly progressive glomerulonephritis","correct":false,"visible":false},{"text":"Minimal change disease","correct":true,"visible":false}]},{"id":12110,"text":"Which of the following arteries supplies the upper part of the ureter?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 520.","responses":[{"text":"Internal iliac artery","correct":false,"visible":false},{"text":"External iliac artery","correct":false,"visible":false},{"text":"Common iliac artery","correct":false,"visible":false},{"text":"Gonadal artery","correct":false,"visible":false},{"text":"Renal artery","correct":true,"visible":false}]},{"id":12111,"text":"Which of the following increase in metabolic alkalosis?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 416.","responses":[{"text":"HCO3 only","correct":false,"visible":false},{"text":"Plasma pH and HCO3","correct":true,"visible":false},{"text":"Plasma pH only","correct":false,"visible":false},{"text":"Plasma pH and pCO2","correct":false,"visible":false},{"text":"Plasma pH and lactic acid","correct":false,"visible":false}]},{"id":12112,"text":"Change occurs in which part of the bladder when it is filled with urine?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 456.","responses":[{"text":"Fundus","correct":false,"visible":false},{"text":"Trigone","correct":false,"visible":false},{"text":"Body","correct":true,"visible":false},{"text":"Neck","correct":false,"visible":false},{"text":"Base","correct":false,"visible":false}]},{"id":12113,"text":"What is the osmolarity of the interstitial fluid in the renal medulla?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 370.","responses":[{"text":"1800 mOsm/L","correct":false,"visible":false},{"text":"600 mOsm/L","correct":false,"visible":false},{"text":"1200 mOsm/L","correct":true,"visible":false},{"text":"1000 mOsm/L","correct":false,"visible":false},{"text":"800 mOsm/L","correct":false,"visible":false}]},{"id":12114,"text":"Increased secretion of aldosterone leads to which of the following?","explanation":"Aldosterone is a hormone secreted by the adrenal cortex that acts primarily on the renal collecting tubules. Its primary effects are to promote sodium reabsorption and potassium secretion. Along with this, aldosterone promotes the secretion of hydrogen ions (H⁺) into the urine. As a result:\r\n\r\n1. **Increased Sodium Reabsorption**: This helps in retaining sodium in the body, potentially leading to an expanded extracellular fluid volume but does not lead to hypernatremia unless there's an inadequate water intake or ADH response.\r\n   \r\n2. **Increased Potassium Secretion**: This can lead to a lowered blood potassium level, or hypokalemia.\r\n   \r\n3. **Increased Hydrogen Ion Secretion**: The increased secretion of H⁺ ions can cause the blood to become more alkaline, resulting in metabolic alkalosis.\r\n\r\nTherefore, increased secretion of aldosterone can lead to metabolic alkalosis, among other potential disturbances.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 398, 960.","responses":[{"text":"Hyponatremia","correct":false,"visible":false},{"text":"Hypernatremia","correct":false,"visible":false},{"text":"Hyperkalemia","correct":false,"visible":false},{"text":"Metabolic acidosis","correct":false,"visible":false},{"text":"Metabolic alkalosis","correct":true,"visible":false}]},{"id":12115,"text":"The kidneys lie at which vertebral level?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 374.","responses":[{"text":"T12-L1","correct":false,"visible":false},{"text":"T12-L4","correct":false,"visible":false},{"text":"T12-L2","correct":false,"visible":false},{"text":"T11-L3","correct":false,"visible":false},{"text":"T12-L3","correct":true,"visible":false}]},{"id":12149,"text":"The renal medulla contains 6-8 pyramids. What is the extension of the cortex between these pyramids called?","explanation":null,"reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 378.","responses":[{"text":"Minor calyx","correct":false,"visible":false},{"text":"Cortical columns","correct":true,"visible":false},{"text":"Major calyx","correct":false,"visible":false},{"text":"Medullary rays","correct":false,"visible":false},{"text":"Cortical rays","correct":false,"visible":false}]},{"id":12150,"text":"A 65-year-old male presented with a complaint of dysuria. His complete urinalysis showed gram-negative rods that were non-lactose fermenting and had swarming movements. What is the most probable cause?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 141.\r\n(2) Levinson W, Chin-Hong P, Joyce EA, Nussbaum J, Schwartz B. Review of Medical Microbiology and Immunology: A Guide to Clinical Infectious Diseases. 15th ed. McGraw-Hill Education; 2018: 661.","responses":[{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Proteus vulgaris","correct":false,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Proteus mirabilis","correct":true,"visible":false},{"text":"Enterococcus faecalis","correct":false,"visible":false}]},{"id":12151,"text":"Where are specialized cells with primary and secondary processes found?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 397.","responses":[{"text":"Distal convoluted tubule","correct":false,"visible":false},{"text":"Proximal convoluted tubule","correct":false,"visible":false},{"text":"Macula densa","correct":false,"visible":false},{"text":"Bowman's capsule","correct":true,"visible":false},{"text":"Collecting duct","correct":false,"visible":false}]},{"id":12152,"text":"Which urea transporter is present in the loop of Henle for urea secretion?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 371.","responses":[{"text":"UT-1","correct":false,"visible":false},{"text":"UT-5","correct":false,"visible":false},{"text":"UT-2","correct":true,"visible":false},{"text":"UT-3","correct":false,"visible":false},{"text":"UT-4","correct":false,"visible":false}]},{"id":12153,"text":"Which of the following hormones acts on the principal cells of the nephrons?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 387.","responses":[{"text":"Parathyroid hormone","correct":false,"visible":false},{"text":"Aldosterone","correct":true,"visible":false},{"text":"Anti-diuretic hormone","correct":false,"visible":false},{"text":"Angiotensin","correct":false,"visible":false},{"text":"Cortisol","correct":false,"visible":false}]},{"id":12154,"text":"Which of the following is not true about sodium reabsorption in the proximal convoluted tubule?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 349.","responses":[{"text":"65% of filtered load is reabsorbed","correct":false,"visible":false},{"text":"80% of filtered load is reabsorbed","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Reabsorption occurs through Na⁺-H⁺ ATPase pump","correct":false,"visible":false},{"text":"Sodium shares the same transporter as glucose","correct":false,"visible":false}]},{"id":12220,"text":"Which substances are required for the de novo synthesis of pyrimidines?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 302.","responses":[{"text":"Glutamine and aspartate","correct":false,"visible":false},{"text":"Glutamine, carbon dioxide, and aspartate","correct":true,"visible":false},{"text":"Aspartate only","correct":false,"visible":false},{"text":"NADH only","correct":false,"visible":false},{"text":"Glutamine and NADH","correct":false,"visible":false}]},{"id":12224,"text":"Increased HCO₃⁻ excretion replaces Cl⁻ in the urine due to which of the following?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 414.","responses":[{"text":"Increased Na⁺-H⁺ exchange","correct":false,"visible":false},{"text":"Decreased Na⁺-H⁺ exchange","correct":false,"visible":false},{"text":"Retention of acid metabolites","correct":true,"visible":false},{"text":"Ketoacidosis","correct":false,"visible":false},{"text":"Increased acid secretion","correct":false,"visible":false}]},{"id":12225,"text":"In which part of the nephron is the Na⁺-K⁺-2Cl⁻ transporter most abundant?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 351.","responses":[{"text":"Collecting duct","correct":false,"visible":false},{"text":"Proximal convoluted tubules","correct":false,"visible":false},{"text":"Thin ascending limb of loop of Henle","correct":false,"visible":false},{"text":"Thin descending limb of loop of Henle","correct":false,"visible":false},{"text":"Thick ascending limb of loop of Henle","correct":true,"visible":false}]},{"id":12227,"text":"What is the mechanism by which calcium ions are reabsorbed in the proximal convoluted tubule?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 391.","responses":[{"text":"Transcellular route","correct":false,"visible":false},{"text":"Paracellular route","correct":true,"visible":false},{"text":"Facilitated diffusion","correct":false,"visible":false},{"text":"Secondary active transport","correct":false,"visible":false},{"text":"Active transport","correct":false,"visible":false}]},{"id":12229,"text":"A female comes into the clinic with oral ulcers, hematuria, and +1 proteinuria. 1-2 white blood cells/HPF are found on urinalysis. What is the most probable diagnosis?","explanation":"The clinical presentation of oral ulcers combined with hematuria and proteinuria is suggestive of systemic lupus erythematosus (SLE), a multisystem autoimmune disease. When SLE affects the kidneys, it is referred to as lupus nephritis.\r\n\r\n1. **Oral ulcers** are one of the common mucocutaneous manifestations of SLE.\r\n   \r\n2. **Hematuria and Proteinuria**: These are signs of kidney involvement, and lupus nephritis can manifest with a variety of renal syndromes, ranging from mild hematuria or proteinuria to rapidly progressive glomerulonephritis.\r\n\r\n3. **White Blood Cells in Urine**: The presence of white blood cells in the urine can indicate an inflammatory process in the kidneys.\r\n\r\nWhile other options listed can cause hematuria and proteinuria, the combination of oral ulcers and the described urinalysis findings make lupus nephritis the most probable diagnosis in this context.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 480.","responses":[{"text":"IgA nephropathy","correct":false,"visible":false},{"text":"Membranous nephropathy","correct":false,"visible":false},{"text":"Lupus nephritis","correct":true,"visible":false},{"text":"Acid excretion","correct":false,"visible":false},{"text":"Glomerulonephritis","correct":false,"visible":false}]},{"id":12230,"text":"A young man presents to the outpatient department with urethral discharge. Urinalysis shows neutrophils but there are no bacteria found. What is the most likely cause?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132.","responses":[{"text":"Escherichia coli","correct":false,"visible":false},{"text":"Treponema pallidum","correct":false,"visible":false},{"text":"Candida albicans","correct":false,"visible":false},{"text":"Chlamydia trachomatis","correct":true,"visible":false},{"text":"Coxiella burnetii","correct":false,"visible":false}]},{"id":12231,"text":"What should be the target blood pressure of a person having chronic kidney failure with 1+ proteinuria?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 417.","responses":[{"text":"140/90 mmHg","correct":false,"visible":false},{"text":"160/100 mmHg","correct":false,"visible":false},{"text":"150/90 mmHg","correct":false,"visible":false},{"text":"130/80 mmHg","correct":false,"visible":false},{"text":"125/75 mmHg","correct":true,"visible":false}]},{"id":12232,"text":"A patient complains of dysuria, fever, urinary frequency, and hematuria. His urinalysis shows numerous white blood cells, nitrite positive, and few red blood cells. What is true about the most common causative agent?","explanation":null,"reference":"(1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132. \r\n\r\n(2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 143.","responses":[{"text":"Catalase negative gram-positive rods","correct":false,"visible":false},{"text":"Gram-negative spiral rods","correct":false,"visible":false},{"text":"Urease positive gram-negative rods","correct":false,"visible":false},{"text":"Catalase positive gram-positive rods","correct":false,"visible":false},{"text":"Indole positive gram-negative rods","correct":true,"visible":false}]},{"id":12233,"text":"Which of the following is an extrinsic cause of unilateral partial obstruction of the ureter?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 950.","responses":[{"text":"Congenital vesicoureteral reflux","correct":false,"visible":false},{"text":"Retroperitoneal fibrosis","correct":true,"visible":false},{"text":"Renal calculi","correct":false,"visible":false},{"text":"Ectopic fused kidney","correct":false,"visible":false},{"text":"Horseshoe kidney","correct":false,"visible":false}]},{"id":12238,"text":"A man came with the complaint of right lumbar pain and hematuria for four hours. Which of the following should be the choice of investigation?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 389.","responses":[{"text":"Ultrasound KUB","correct":true,"visible":false},{"text":"Plain radiography KUB","correct":false,"visible":false},{"text":"MRI scan","correct":false,"visible":false},{"text":"CT scan","correct":false,"visible":false},{"text":"X-ray KUB","correct":false,"visible":false}]},{"id":12239,"text":"A 2.2x2.4 cm mass is accidentally found on ultrasound at the lower pole of the kidney. What should be the subsequent investigation of choice?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 389.","responses":[{"text":"CT scan","correct":true,"visible":false},{"text":"Plain radiography KUB","correct":false,"visible":false},{"text":"MRI pelvis","correct":false,"visible":false},{"text":"Ultrasound KUB","correct":false,"visible":false},{"text":"X-ray KUB","correct":false,"visible":false}]},{"id":12240,"text":"Which of the following structures holds the kidney in its position?","explanation":null,"reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 515, 516.","responses":[{"text":"Perinephric fat","correct":false,"visible":false},{"text":"Renal fascia","correct":false,"visible":false},{"text":"Collagen bundles","correct":false,"visible":false},{"text":"All of these","correct":true,"visible":false},{"text":"Paranephric fat","correct":false,"visible":false}]},{"id":12241,"text":"Which of the following urine culture results gives the diagnosis of urinary tract infection?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 131.","responses":[{"text":"100-1000 CFU/ml","correct":false,"visible":false},{"text":"50000-100000 CFU/ml","correct":false,"visible":false},{"text":"100000-200000 CFU/ml","correct":true,"visible":false},{"text":"1000-5000 CFU/ml","correct":false,"visible":false},{"text":"10000-100000 CFU/ml","correct":false,"visible":false}]},{"id":12242,"text":"At the end of an information care session, the patient briefly summarises which of the following?","explanation":null,"reference":"Dow lecture slides, Renal-I Module, Behavioural Science slides, Topic: Information Care.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Details of the doctor","correct":false,"visible":false},{"text":"Details of the drug","correct":false,"visible":false},{"text":"Details of the disease","correct":false,"visible":false},{"text":"Details of the disease, drug, and doctor","correct":true,"visible":false}]},{"id":12243,"text":"Which of the following are delicate matrix-forming cells present among the glomerular capillaries, having contractile nature, and are phagocytic?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 400.","responses":[{"text":"Podocytes","correct":false,"visible":false},{"text":"Distal convoluted tubule cells","correct":false,"visible":false},{"text":"Mesangial cells","correct":true,"visible":false},{"text":"Juxtaglomerular cells","correct":false,"visible":false},{"text":"Basal lamina cells","correct":false,"visible":false}]},{"id":12244,"text":"Which of the following is a congenital abnormality that occurs due to the persistence of urachus resulting in an opening between the umbilicus and the urinary bladder?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 255.","responses":[{"text":"Urachal sinus","correct":false,"visible":false},{"text":"Urachal fistula","correct":true,"visible":false},{"text":"Urachal cyst","correct":false,"visible":false},{"text":"Urogenital sinus","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":12245,"text":"Which of the following is the remnant of the urachus?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 58.","responses":[{"text":"Umbilicus","correct":false,"visible":false},{"text":"Medial umbilical ligament","correct":false,"visible":false},{"text":"Lateral umbilical ligament","correct":false,"visible":false},{"text":"Umbilical artery","correct":false,"visible":false},{"text":"Median umbilical ligament","correct":true,"visible":false}]},{"id":12246,"text":"A two-year-old boy presented with recurrent urinary tract infections. What is the most likely cause?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 132.","responses":[{"text":"Dysplastic kidney","correct":false,"visible":false},{"text":"Minimal change disease","correct":false,"visible":false},{"text":"Congenital vesicoureteral reflux","correct":true,"visible":false},{"text":"Horseshoe kidney","correct":false,"visible":false},{"text":"Polycystic kidney disease","correct":false,"visible":false}]},{"id":12247,"text":"Which of the following is the narrowest part of the ureter, well above the urinary bladder, where stones can get lodged?","explanation":"The ureter has several anatomically narrow points where kidney stones (calculi) are more likely to get lodged. These narrow points include:\r\n\r\n1. The **ureteropelvic junction** (where the renal pelvis transitions to the ureter).\r\n2. The crossing at the **pelvic brim** (also known as the iliac vessels or pelvic inlet).\r\n3. The **ureterovesical junction** (where the ureter enters the bladder).\r\n\r\nOf the options provided, the **pelvic brim** represents the narrow constriction well above the urinary bladder where stones can get lodged. The pelvic brim is the site where the ureter crosses over the bifurcation of the common iliac artery or the beginning of the external iliac artery.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 526.","responses":[{"text":"Pelvicalyceal junction","correct":false,"visible":false},{"text":"Major calyx","correct":false,"visible":false},{"text":"Minor calyx","correct":false,"visible":false},{"text":"Pelvic brim","correct":true,"visible":false},{"text":"Bladder wall","correct":false,"visible":false}]},{"id":12248,"text":"A female patient was on antibiotic therapy for urinary tract infections. She later developed a fever and rash.  Her urine had increased eosinophils. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 127.","responses":[{"text":"Renal papillary necrosis","correct":false,"visible":false},{"text":"Acute tubular necrosis","correct":false,"visible":false},{"text":"Nephritic syndrome","correct":false,"visible":false},{"text":"Acute interstitial nephritis","correct":true,"visible":false},{"text":"Drug induced interstitial nephritis","correct":false,"visible":false}]},{"id":12249,"text":"One-third of total body water is found in which of the following compartments?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 4.","responses":[{"text":"Interstitial","correct":false,"visible":false},{"text":"Intracellular","correct":false,"visible":false},{"text":"Plasma","correct":false,"visible":false},{"text":"Intracellular and interstitial","correct":false,"visible":false},{"text":"Extracellular","correct":true,"visible":false}]},{"id":12261,"text":"Which of the following is measured using para-amino hippuric acid?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 350.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Renal plasma flow","correct":true,"visible":false},{"text":"Glomerular filtration rate","correct":false,"visible":false},{"text":"Urine output","correct":false,"visible":false},{"text":"Renal blood flow","correct":false,"visible":false}]},{"id":12262,"text":"Which of the following is incorrect about the development of the urogenital system?","explanation":null,"reference":"(1) Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 268, 508. \r\n\r\n(2) Embryonic development of the bladder and urethra - wikilectures. Accessed October 19, 2022. https://www.wikilectures.eu/w/Embryonic_development_of_the_Bladder_and_Urethra","responses":[{"text":"Urethral folds merge on the ventral aspect of the penile urethra","correct":false,"visible":false},{"text":"All statements are correct","correct":false,"visible":false},{"text":"Prostatic urethra is derived from the pelvic part of the urogenital sinus","correct":false,"visible":false},{"text":"Membranous urethra is derived from the phallic part of the urogenital sinus","correct":true,"visible":false},{"text":"Hypospadias is the failure of the closure of the urethral folds","correct":false,"visible":false}]},{"id":12263,"text":"Which of the following statements is correct about the urogenital system?","explanation":null,"reference":"Moore KL, Persaud TVN, Torchia MG. The Developing Human: Clinically Oriented Embryology. 10th ed. Elsevier; 2016: 241, 245, 246.","responses":[{"text":"Podocytes are derived from the endoderm","correct":false,"visible":false},{"text":"Macula densa secrete renin","correct":false,"visible":false},{"text":"Kidney become functional at the end of 2nd trimester","correct":false,"visible":false},{"text":"Distal tubules show brush border","correct":false,"visible":false},{"text":"Collecting ducts are derived from the mesoderm","correct":true,"visible":false}]},{"id":12264,"text":"A 65-year-old man came with a complaint of recurrent flank pain. Ultrasound revealed hydronephrosis with distension of the pelvis and calyces but the bladder and ureters were normal. What is the most likely cause of his complaint?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 933, 950.","responses":[{"text":"Ectopic fused kidney","correct":false,"visible":false},{"text":"Retroperitoneal fibrosis","correct":false,"visible":false},{"text":"Congenital vesicoureteral reflux","correct":false,"visible":false},{"text":"Prostatic hyperplasia","correct":true,"visible":false},{"text":"Horseshoe kidney","correct":false,"visible":false}]},{"id":12265,"text":"A 65-year-old male came with complaints of fever, hematuria, and flank pain. He had white blood cell casts in his urine and his culture showed 10⁴ CFU/ml. What direction of investigation should be followed?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 428.","responses":[{"text":"10⁴ CFU/ml is not significant","correct":false,"visible":false},{"text":"Go for a pyelogram","correct":false,"visible":false},{"text":"Urine culture should be done again","correct":false,"visible":false},{"text":"Treat as a case of urinary tract infection","correct":true,"visible":false},{"text":"An ultrasound should be performed","correct":false,"visible":false}]},{"id":12266,"text":"Dialysis is done in end stage renal disease as a replacement for renal function. Which of the following is correct regarding it?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 422.","responses":[{"text":"Preservation of arm veins is not important","correct":false,"visible":false},{"text":"Long term dialysis is done by two way catheter in the central vein","correct":false,"visible":false},{"text":"Long term catheter is placed in the femoral vein","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Formation of arteriovenous fistula","correct":true,"visible":false}]},{"id":12267,"text":"What is true about hemodialysis of patient with end stage renal disease?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 423.","responses":[{"text":"Can be done at home 4 times per day","correct":false,"visible":false},{"text":"No need for hemodialysis in acute kidney injury","correct":false,"visible":false},{"text":"No restriction on diet and fluid intake","correct":false,"visible":false},{"text":"4 hour session thrice a week","correct":true,"visible":false},{"text":"Screening for hepatitis C is not required","correct":false,"visible":false}]},{"id":12268,"text":"Which of the following structures is lined by transitional epithelium?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 406.","responses":[{"text":"Nephron","correct":false,"visible":false},{"text":"Urinary bladder","correct":true,"visible":false},{"text":"Prostate gland","correct":false,"visible":false},{"text":"Collecting duct","correct":false,"visible":false},{"text":"Urethra","correct":false,"visible":false}]},{"id":12269,"text":"Which substance donates a single carbon atom in the pyrimidine ring?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 302.","responses":[{"text":"Carbon dioxide","correct":true,"visible":false},{"text":"Glycine","correct":false,"visible":false},{"text":"Tetrahydrofolate","correct":false,"visible":false},{"text":"Aspartate","correct":false,"visible":false},{"text":"Glutamate","correct":false,"visible":false}]},{"id":12270,"text":"Which of the following is involved in the de novo synthesis of both purines and pyrimidines?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 292, 302.","responses":[{"text":"Tetrahydrofolate","correct":false,"visible":false},{"text":"Glutamine, carbon dioxide, and aspartate","correct":true,"visible":false},{"text":"Aspartate","correct":false,"visible":false},{"text":"Glutamine","correct":false,"visible":false},{"text":"Glycine","correct":false,"visible":false}]},{"id":12271,"text":"Bilateral agenesis of the kidneys is associated with which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 125.","responses":[{"text":"Polyhydramnios","correct":false,"visible":false},{"text":"Renal failure later in life","correct":false,"visible":false},{"text":"Hypertension","correct":false,"visible":false},{"text":"Oligohydramnios","correct":true,"visible":false},{"text":"Hypertrophy of kidneys","correct":false,"visible":false}]},{"id":12272,"text":"Which of the following causes an increase in the glomerular filtration rate?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 336, 337.","responses":[{"text":"Sympathetic nervous system stimulation","correct":false,"visible":false},{"text":"Urinary tract obstruction","correct":false,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Endothelial derived nitric oxide","correct":true,"visible":false},{"text":"Angiotensin II","correct":false,"visible":false}]},{"id":12273,"text":"Which of the following is synthesized by the kidney and acts on the intestine?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 322.","responses":[{"text":"Erythropoietin","correct":false,"visible":false},{"text":"Albumin","correct":false,"visible":false},{"text":"Calcitriol","correct":true,"visible":false},{"text":"Parathyroid hormone","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false}]},{"id":12274,"text":"Which of the following are interrelated processes of the nephron?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 329.","responses":[{"text":"Filtration, reabsorption, and secretion","correct":true,"visible":false},{"text":"Filtration, secretion, and excretion","correct":false,"visible":false},{"text":"Filtration and excretion","correct":false,"visible":false},{"text":"Filtration, reabsorption, and excretion","correct":false,"visible":false},{"text":"Reabsorption, secretion, and excretion","correct":false,"visible":false}]},{"id":12275,"text":"Which is true regrading juxtaglomerular apparatus?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 236.","responses":[{"text":"Macula densa is a part of the proximal convoluted tubule","correct":false,"visible":false},{"text":"Juxtaglomerular cells secrete renin","correct":true,"visible":false},{"text":"Juxtaglomerular cells are found in both afferent and efferent arterioles","correct":false,"visible":false},{"text":"Macula densa cells secrete renin","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":12276,"text":"Which of the following is not a congenital disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 125.","responses":[{"text":"Horseshoe kidney","correct":false,"visible":false},{"text":"Renal agenesis","correct":false,"visible":false},{"text":"Polycystic kidney disease","correct":false,"visible":false},{"text":"Renal stones","correct":true,"visible":false},{"text":"Medullary cystic kidney disease","correct":false,"visible":false}]},{"id":12277,"text":"Sodium ions are reabsorbed in exchange of which of the following ions in the proximal convoluted tubule?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 349.","responses":[{"text":"Glucose","correct":false,"visible":false},{"text":"Potassium ions","correct":false,"visible":false},{"text":"Chloride ions","correct":false,"visible":false},{"text":"Hydrogen ions","correct":true,"visible":false},{"text":"Phosphate ions","correct":false,"visible":false}]},{"id":12278,"text":"A patient on dialysis could not find a kidney donor in the family. He is about to receive a kidney transplant from someone who is about to die. What will the donor be called?","explanation":null,"reference":"Cadaveric donors. The Organ Donation and Transplantation Alliance. Accessed October 19, 2022. https://www.organdonationalliance.org/glossary/cadaveric-donors/","responses":[{"text":"Genetically related donor","correct":false,"visible":false},{"text":"Non-related donor","correct":false,"visible":false},{"text":"Cadaveric donor","correct":true,"visible":false},{"text":"Living donor","correct":false,"visible":false},{"text":"Living unrelated donor","correct":false,"visible":false}]},{"id":12279,"text":"A 4-year-old boy showed signs of diffuse effacement of foot processes on electron microscopy. What is correct about the disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 128.","responses":[{"text":"Dramatic response to corticosteroids","correct":true,"visible":false},{"text":"Progression to chronic renal failure","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Spike and dome appearance","correct":false,"visible":false},{"text":"Presence of immune complex deposits","correct":false,"visible":false}]}
]

export default a